":[\"S\",\"o\",\"r\",\"r\",\"o\",\"w\",\";\",\" \",\"a\",\"f\",\"f\",\"l\",\"i\",\"c\",\"t\",\"i\",\"o\",\"n\",\".\"]},\"Le deuil\":{\"type\":\"txt\",\"ans\":[\"B\",\"e\",\"r\",\"e\",\"a\",\"v\",\"e\",\"m\",\"e\",\"n\",\"t\",\";\",\" \",\"g\",\"r\",\"i\",\"e\",\"f\",\".\"]},\"La douleur\":{\"type\":\"txt\",\"ans\":[\"P\",\"a\",\"i\",\"n\",\";\",\" \",\"s\",\"u\",\"f\",\"f\",\"e\",\"r\",\"i\",\"n\",\"g\",\".\"]},\"Un \\u00e9tat d&#039;\\u00e2me\":{\"type\":\"txt\",\"ans\":[\"Q\",\"u\",\"a\",\"l\",\"m\",\";\",\" \",\"f\",\"e\",\"e\",\"l\",\"i\",\"n\",\"g\",\".\"]},\"La langueur\":{\"type\":\"txt\",\"ans\":[\"L\",\"i\",\"s\",\"t\",\"l\",\"e\",\"s\",\"s\",\"n\",\"e\",\"s\",\"s\",\".\"]},\"Une larme\":{\"type\":\"txt\",\"ans\":[\"T\",\"e\",\"a\",\"r\",\".\"]},\"La peine\":{\"type\":\"txt\",\"ans\":[\"S\",\"o\",\"r\",\"r\",\"o\",\"w\",\";\",\" \",\"g\",\"r\",\"i\",\"e\",\"f\",\".\"]},\"Une raison\":{\"type\":\"txt\",\"ans\":[\"R\",\"e\",\"a\",\"s\",\"o\",\"n\",\".\"]},\"Le toit\":{\"type\":\"txt\",\"ans\":[\"R\",\"o\",\"o\",\"f\",\".\"]},\"La trahison\":{\"type\":\"txt\",\"ans\":[\"B\",\"e\",\"t\",\"r\",\"a\",\"y\",\"a\",\"l\",\".\"]},\"S&#039;\\u00e9c\\u0153urer\":{\"type\":\"txt\",\"ans\":[\"T\",\"o\",\" \",\"s\",\"i\",\"c\",\"k\",\"e\",\"n\",\" \",\"o\",\"n\",\"e\",\"s\",\"e\",\"l\",\"f\",\" \",\"\\/\",\" \",\"b\",\"e\",\"c\",\"o\",\"m\",\"e\",\" \",\"n\",\"a\",\"u\",\"s\",\"e\",\"a\",\"t\",\"e\",\"d\",\".\"]},\"\\u00c9voquer\":{\"type\":\"txt\",\"ans\":[\"T\",\"o\",\" \",\"e\",\"v\",\"o\",\"k\",\"e\",\".\"]},\"Pleurer\":{\"type\":\"txt\",\"ans\":[\"T\",\"o\",\" \",\"c\",\"r\",\"y\",\".\"]},\"Par terre\":{\"type\":\"txt\",\"ans\":[\"O\",\"n\",\" \",\"t\",\"h\",\"e\",\" \",\"g\",\"r\",\"o\",\"u\",\"n\",\"d\",\".\"]},\"\\u00c0 part\":{\"type\":\"txt\",\"ans\":[\"A\",\"p\",\"a\",\"r\",\"t\",\" \",\"f\",\"r\",\"o\",\"m\",\",\",\" \",\"e\",\"x\",\"c\",\"e\",\"p\",\"t\",\" \",\"f\",\"o\",\"r\",\".\"]},\"Quand m\\u00eame\":{\"type\":\"txt\",\"ans\":[\"N\",\"e\",\"v\",\"e\",\"r\",\"t\",\"h\",\"e\",\"l\",\"e\",\"s\",\"s\",\",\",\" \",\"a\",\"n\",\"y\",\"w\",\"a\",\"y\",\".\"]},\"Sinon\":{\"type\":\"txt\",\"ans\":[\"O\",\"t\",\"h\",\"e\",\"r\",\"w\",\"i\",\"s\",\"e\",\".\"]},\"Tandis que\":{\"type\":\"txt\",\"ans\":[\"W\",\"h\",\"i\",\"l\",\"e\",\".\"]},\"Les Lieux\":{\"type\":\"txt\",\"ans\":[\"U\",\"n\",\" \",\"a\",\"r\",\"r\",\"\\u00ea\",\"t\",\" \",\"d\",\"&#039;\",\"a\",\"u\",\"t\",\"o\",\"b\",\"u\",\"s\",\".\"]},\"Une banlieue\":{\"type\":\"txt\",\"ans\":[\"S\",\"u\",\"b\",\"u\",\"r\",\"b\",\";\",\" \",\"o\",\"u\",\"t\",\"s\",\"k\",\"i\",\"r\",\"t\",\"s\",\".\"]},\"Une caserne de pompiers\":{\"type\":\"txt\",\"ans\":[\"F\",\"i\",\"r\",\"e\",\" \",\"s\",\"t\",\"a\",\"t\",\"i\",\"o\",\"n\",\".\"]},\"Le centre-ville\":{\"type\":\"txt\",\"ans\":[\"C\",\"i\",\"t\",\"y\",\"\\/\",\"t\",\"o\",\"w\",\"n\",\" \",\"c\",\"e\",\"n\",\"t\",\"e\",\"r\",\";\",\" \",\"d\",\"o\",\"w\",\"n\",\"t\",\"o\",\"w\",\"n\",\".\"]},\"Un cin\\u00e9ma\":{\"type\":\"txt\",\"ans\":[\"C\",\"i\",\"n\",\"e\",\"m\",\"a\",\";\",\" \",\"m\",\"o\",\"v\",\"i\",\"e\",\" \",\"t\",\"h\",\"e\",\"a\",\"t\",\"e\",\"r\",\".\"]},\"La circulation\":{\"type\":\"txt\",\"ans\":[\"T\",\"r\",\"a\",\"f\",\"f\",\"i\",\"c\",\".\"]},\"Les clous\":{\"type\":\"txt\",\"ans\":[\"C\",\"r\",\"o\",\"s\",\"s\",\"w\",\"a\",\"l\",\"k\",\".\"]},\"Un commissariat de police\":{\"type\":\"txt\",\"ans\":[\"P\",\"o\",\"l\",\"i\",\"c\",\"e\",\" \",\"s\",\"t\",\"a\",\"t\",\"i\",\"o\",\"n\",\".\"]},\"Un \\u00e9difice\":{\"type\":\"txt\",\"ans\":[\"B\",\"u\",\"i\",\"l\",\"d\",\"i\",\"n\",\"g\",\".\"]},\"Un gratte-ciel\":{\"type\":\"txt\",\"ans\":[\"S\",\"k\",\"y\",\"s\",\"c\",\"r\",\"a\",\"p\",\"e\",\"r\",\".\"]},\"Un h\\u00f4tel de ville\":{\"type\":\"txt\",\"ans\":[\"C\",\"i\",\"t\",\"y\",\"\\/\",\"t\",\"o\",\"w\",\"n\",\" \",\"h\",\"a\",\"l\",\"l\",\".\"]},\"Un jardin public\":{\"type\":\"txt\",\"ans\":[\"P\",\"u\",\"b\",\"l\",\"i\",\"c\",\" \",\"g\",\"a\",\"r\",\"d\",\"e\",\"n\",\".\"]},\"Un logement\\/une habitation\":{\"type\":\"txt\",\"ans\":[\"H\",\"o\",\"u\",\"s\",\"i\",\"n\",\"g\",\".\"]},\"Un mus\\u00e9e\":{\"type\":\"txt\",\"ans\":[\"M\",\"u\",\"s\",\"e\",\"u\",\"m\",\".\"]},\"Le palais de justice\":{\"type\":\"txt\",\"ans\":[\"C\",\"o\",\"u\",\"r\",\"t\",\"h\",\"o\",\"u\",\"s\",\"e\",\".\"]},\"Une place\":{\"type\":\"txt\",\"ans\":[\"S\",\"q\",\"u\",\"a\",\"r\",\"e\",\";\",\" \",\"p\",\"l\",\"a\",\"z\",\"a\",\".\"]},\"La pr\\u00e9fecture de police\":{\"type\":\"txt\",\"ans\":[\"P\",\"o\",\"l\",\"i\",\"c\",\"e\",\" \",\"h\",\"e\",\"a\",\"d\",\"q\",\"u\",\"a\",\"r\",\"t\",\"e\",\"r\",\"s\",\".\"]},\"Un quartier\":{\"type\":\"txt\",\"ans\":[\"N\",\"e\",\"i\",\"g\",\"h\",\"b\",\"o\",\"r\",\"h\",\"o\",\"o\",\"d\",\".\"]},\"Une station de m\\u00e9tro\":{\"type\":\"txt\",\"ans\":[\"S\",\"u\",\"b\",\"w\",\"a\",\"y\",\" \",\"s\",\"t\",\"a\",\"t\",\"i\",\"o\",\"n\",\".\"]},\"Un croisement\":{\"type\":\"txt\",\"ans\":[\"I\",\"n\",\"t\",\"e\",\"r\",\"s\",\"e\",\"c\",\"t\",\"i\",\"o\",\"n\",\".\"]},\"Un embouteillage\":{\"type\":\"txt\",\"ans\":[\"T\",\"r\",\"a\",\"f\",\"f\",\"i\",\"c\",\" \",\"j\",\"a\",\"m\",\".\"]},\"Un feu (tricolore)\":{\"type\":\"txt\",\"ans\":[\"T\",\"r\",\"a\",\"f\",\"f\",\"i\",\"c\",\" \",\"l\",\"i\",\"g\",\"h\",\"t\",\".\"]},\"Un panneau\":{\"type\":\"txt\",\"ans\":[\"R\",\"o\",\"a\",\"d\",\" \",\"s\",\"i\",\"g\",\"n\",\".\"]},\"Un panneau d&#039;affichage\":{\"type\":\"txt\",\"ans\":[\"B\",\"i\",\"l\",\"l\",\"b\",\"o\",\"a\",\"r\",\"d\",\".\"]},\"Un pont\":{\"type\":\"txt\",\"ans\":[\"B\",\"r\",\"i\",\"d\",\"g\",\"e\",\".\"]},\"Un rond-point\":{\"type\":\"txt\",\"ans\":[\"R\",\"o\",\"t\",\"a\",\"r\",\"y\",\";\",\" \",\"r\",\"o\",\"u\",\"n\",\"d\",\"a\",\"b\",\"o\",\"u\",\"t\",\".\"]},\"Une rue\":{\"type\":\"txt\",\"ans\":[\"S\",\"t\",\"r\",\"e\",\"e\",\"t\",\".\"]},\"Les transports en commun\":{\"type\":\"txt\",\"ans\":[\"P\",\"u\",\"b\",\"l\",\"i\",\"c\",\" \",\"t\",\"r\",\"a\",\"n\",\"s\",\"p\",\"o\",\"r\",\"t\",\"a\",\"t\",\"i\",\"o\",\"n\",\".\"]},\"Un trottoir\":{\"type\":\"txt\",\"ans\":[\"S\",\"i\",\"d\",\"e\",\"w\",\"a\",\"l\",\"k\",\".\"]},\"Une voie\":{\"type\":\"txt\",\"ans\":[\"L\",\"a\",\"n\",\"e\",\";\",\" \",\"r\",\"o\",\"a\",\"d\",\";\",\" \",\"t\",\"r\",\"a\",\"c\",\"k\",\".\"]}}}', '[2,21,20,1]', 1),
(61, 'West Civ Final-Classical Legacy', 'lilbigman', '{\"desc\":\"Final Review\",\"contnt\":{\"Greek author of the Iliad and the Odyssey\":{\"type\":\"txt\",\"ans\":[\"Homer\"]},\"Founder and first king of rome\":{\"type\":\"txt\",\"ans\":[\"Romulus\"]},\"Greek tragedian who wrote Oedipus Rex and Antigone\":{\"type\":\"txt\",\"ans\":[\"Sophocles\"]},\"Roman poet who wrote the Aeneid\":{\"type\":\"txt\",\"ans\":[\"vIrgil\"]},\"A Roman general and statesman who played a critical role in the events that led to the demise of the Roman Republic and the rise of the Roman Empire. He became dictator for life before being assassinated.\":{\"type\":\"txt\",\"ans\":[\"Julius Caesar\"]},\"First Roman Emperor who initiated the Pax Romana\":{\"type\":\"txt\",\"ans\":[\"Augustus\"]},\"Father of Geometry\":{\"type\":\"txt\",\"ans\":[\"Euclid\"]},\"A playwright of ancient Athens, known for his sharp, satirical comedies such as Lysistrata and The Clouds, which critiqued society and politics of his time.\":{\"type\":\"txt\",\"ans\":[\"Aristophanes\"]},\"Roman Emperor who converted to Christianity and played a key role in its spread\":{\"type\":\"txt\",\"ans\":[\"Constantine\"]},\"A key figure in the spread of Christianity,\":{\"type\":\"txt\",\"ans\":[\"Paul of Tarsus\"]},\"Central figure of Christianity\":{\"type\":\"txt\",\"ans\":[\"Jesus of Nazareth\"]},\"An ancient Greek mathematician and inventor, known for his contributions to the understanding of the principles of levers, buoyancy, and the mathematical constant \\u03c0.\":{\"type\":\"txt\",\"ans\":[\"Archimedes\"]},\"Greek philosopher who made significant contributions to many areas, including logic, biology, ethics, and metaphysics. He was a student of Plato and teacher to Alexander the Great.\":{\"type\":\"txt\",\"ans\":[\"Aristotle\"]},\"A classical Greek philosopher credited as one of the founders of Western philosophy, famous for his Socratic method of questioning and dialogues that laid the groundwork for future philosophical thought.\":{\"type\":\"txt\",\"ans\":[\"Socrates\"]},\" A student of Socrates and teacher to Aristotle and founded the Academy in Athens and wrote philosophical works that explored justice, politics, and knowledge, including The Republic.\":{\"type\":\"txt\",\"ans\":[\"Plato\"]},\"The process by which Greek culture, language, and influence spread across the regions of the ancient world, particularly after the conquests of Alexander the Great.\":{\"type\":\"txt\",\"ans\":[\"Hellenize\"]},\"A political institution in ancient Rome, initially serving as an advisory body to the kings, and later as the governing body of the Roman Republic and the Empire, composed of Roman aristocrats.\":{\"type\":\"txt\",\"ans\":[\"Senate\"]},\"A period of relative peace and stability across the Roman Empire, which lasted from the reign of Augustus\":{\"type\":\"txt\",\"ans\":[\"Pax Romana\"]}}}', '[21,2]', 1),
(62, 'West Civ Final-  Medieval World', 'lilbigman', '{\"desc\":\"Review for the west Civ final\",\"contnt\":{\"Known for translating the Bible into Latin\":{\"type\":\"txt\",\"ans\":[\"Saint Jerome\"]},\"A Dominican friar and philosopher, is renowned for integrating Aristotelian philosophy with Christian theology, particularly in his work Summa Theologica, which remains a foundational text in Christian theology.\":{\"type\":\"txt\",\"ans\":[\"Thomas Aquinas\"]},\"A Christian philosopher and theologian, wrote The Confessions and The City of God, works that deeply influenced Western Christianity and philosophy, particularly on topics like original sin and grace.\":{\"type\":\"txt\",\"ans\":[\"Augustine of Hippo\"]},\"King of the Franks and later Emperor of the Holy Roman Empire,\\u00a0 united much of Western Europe during the early Middle Ages and promoted education and Christianization in his empire.\":{\"type\":\"txt\",\"ans\":[\"Charlemagne\"]},\"Byzantine Emperor known for his comprehensive codification of Roman law, known as the Corpus Juris Civilis, and for his efforts to reconquer lost Western territories and rebuild Constantinople, including the Hagia Sophia.\":{\"type\":\"txt\",\"ans\":[\"Justinian I\"]},\"A Muslim military leader and Sultan of Egypt and Syria, is best known for his leadership during the Crusades, particularly his recapture of Jerusalem from the Crusaders in 1187.\":{\"type\":\"txt\",\"ans\":[\"Saladin\"]},\"Duke of Normandy who became King of England after his victory at the Battle of Hastings in 1066, drastically reshaping English society, law, and language.\":{\"type\":\"txt\",\"ans\":[\"William the Conqueror\"]},\"In Catholic doctrine, a temporary state or place of purification for souls who have died in a state of grace but still need to be purified before entering heaven.\":{\"type\":\"txt\",\"ans\":[\"Purgatory\"]},\"Grants by the Church that reduced the punishment for sins. They were often sold, leading to controversy and criticism, particularly during the Reformation.\":{\"type\":\"txt\",\"ans\":[\"Indulgences\"]},\"The Muslim-ruled territories on the Iberian Peninsula, which included parts of modern Spain and Portugal, from the early 8th century until the Christian Reconquista culminated in 1492.\":{\"type\":\"txt\",\"ans\":[\"Al-andalus\"]},\"A piece of land granted by a lord to a vassal in exchange for loyalty, military service, or other obligations, particularly in the feudal system.\":{\"type\":\"txt\",\"ans\":[\"Fief\"]},\"A social and economic system in medieval Europe where land was exchanged for loyalty and service. The king granted land to nobles (lords), who in turn provided land or protection to vassals (lesser nobles or knights) in exchange for military service.\":{\"type\":\"txt\",\"ans\":[\"Feudalism\"]},\"The economic system that was prevalent in medieval Europe, based on the manor (a lord\\u2019s estate) where peasants or serfs worked the land in exchange for protection and a place to live.\":{\"type\":\"txt\",\"ans\":[\"Manorialism\"]},\"The head of the Roman Catholic Church, considered the spiritual leader of all Catholics worldwide.\\u00a0\":{\"type\":\"txt\",\"ans\":[\"Pope\"]},\"Clergy members who live under a religious rule, such as monks and nuns, who follow strict vows of poverty, chastity, and obedience. They often live in monastic communities and focus on religious life and devotion.\":{\"type\":\"txt\",\"ans\":[\"Regular Clergy\"]},\" Clergy who do not live in monastic communities but serve in the world. They include priests, bishops, and archbishops who oversee churches and perform sacraments.\":{\"type\":\"txt\",\"ans\":[\"Secular Clergy\"]},\"Sacred rites or rituals in Christianity that are considered a means of receiving divine grace\":{\"type\":\"txt\",\"ans\":[\"Sacraments\"]}}}', '[21,2,19]', 1);
INSERT INTO `decks` (`id`, `name`, `owner`, `data`, `viewdata`, `public`) VALUES
(63, 'West Civ Final- Early Modern Europe', 'lilbigman', '{\"desc\":\"Review for the west final\",\"contnt\":{\"An Italian architect and engineer, is most famous for designing the dome of the Florence Cathedral.\":{\"type\":\"txt\",\"ans\":[\"Brunelleschi\"]},\"A renowned Italian painter and architect, is celebrated for his harmonious and balanced compositions. His masterpieces include The School of Athens and The Sistine Madonna.\":{\"type\":\"txt\",\"ans\":[\"Raphael\"]},\"An Italian sculptor, painter, architect, and poet, is best known for his works such as the Statue of David, the Piet\\u00e0, and the frescoes on the ceiling of the Sistine Chapel in Rome.\":{\"type\":\"txt\",\"ans\":[\"Michelangelo\"]},\"A polymath of the Renaissance, is famous for his contributions to art, science, and engineering. His masterpieces include The Last Supper and Mona Lisa, and his sketches foreshadowed inventions centuries ahead of their time.\":{\"type\":\"txt\",\"ans\":[\"Leonardo da Vinci\"]},\" A Dutch Renaissance humanist and theologian, was an influential scholar who advocated for a return to simple Christian teachings and emphasized education. His work In Praise of Folly critiqued the corruption of the Church and society.\":{\"type\":\"txt\",\"ans\":[\"Erasmus\"]},\"Is best known for writing Utopia, a work that described an ideal society and critiqued contemporary European politics and social practices.\":{\"type\":\"txt\",\"ans\":[\"Thomas More\"]},\"An Italian statesman and ruler of Florence, was a significant patron of the arts and an important figure in the Renaissance. He supported artists like Leonardo da Vinci, Michelangelo, and Botticelli.\":{\"type\":\"txt\",\"ans\":[\"Lorenzo de Medici\"]},\"Is famous for his voyage to India by sea\":{\"type\":\"txt\",\"ans\":[\"Vasco da Gama\"]},\"Is credited with &quot;discovering&quot; the Americas in 1492, though he believed he had found a new route to Asia. His voyages opened the way for the European exploration and colonization of the Americas.\":{\"type\":\"txt\",\"ans\":[\"Christopher Columbus\"]},\" A Spanish conquistador who led the expedition that resulted in the fall of the Aztec Empire in Mexico\":{\"type\":\"txt\",\"ans\":[\"Hernan Cortes\"]},\"A German monk and theologian, is best known for initiating the Protestant Reformation by posting his 95 Theses in 1517, challenging the Catholic Church&#039;s practices, especially the sale of indulgences.\":{\"type\":\"txt\",\"ans\":[\"Martin Luther\"]},\"An English theologian and scholar, is known for translating the Bible into English and for his criticisms of the Catholic Church, which laid the groundwork for later Protestant reforms.\":{\"type\":\"txt\",\"ans\":[\"John\\u00a0Wycliff \"]},\"Former\\u00a0King of England who\\u00a0is famous for his role in the English Reformation, particularly for breaking with the Roman Catholic Church in the 1530s and establishing the Church of England, also had SIX wives and LEGENDARY appetite\":{\"type\":\"txt\",\"ans\":[\"Henry VIII\"]},\"A Catholic religious order formally known as the Society of Jesus, founded by St. Ignatius of Loyola in 1540. Became known for their missionary work, education, and efforts to reform the Church during the Counter-Reformation.\":{\"type\":\"txt\",\"ans\":[\"Jesuits\"]},\"A radical Protestant sect that emerged during the Reformation who rejected infant baptism\":{\"type\":\"txt\",\"ans\":[\"Anabaptists\"]},\"The widespread exchange of plants, animals, diseases, and cultures between the Old World and the New World following Columbus&#039;s voyages. It had profound effects on both sides, including the introduction of new crops and livestock, but also the spread of diseases like smallpox.\":{\"type\":\"txt\",\"ans\":[\"Columbian Exchange\"]},\"An economic theory and it held that a nation&#039;s wealth and power were best served by increasing exports.\":{\"type\":\"txt\",\"ans\":[\"Mercantilism\"]},\"A system in which wealthy and powerful individuals or families, often in Renaissance Italy, provided financial support to artists, scholars, and intellectuals in exchange for their work. This system helped fuel the Renaissance by allowing the creation of iconic works of art, architecture, and literature.\":{\"type\":\"txt\",\"ans\":[\"Patronage\"]},\"A political treatise by the Italian Renaissance political theorist Niccol\\u00f2 Machiavelli. It is often seen as a guidebook for rulers, advocating for pragmatic, sometimes ruthless political tactics, famously stating that &quot;the ends justify the means.&quot;\":{\"type\":\"txt\",\"ans\":[\"The Prince\"]},\"A term used to describe the European rulers in the late 15th and early 16th centuries who centralized power in their states, reduced the influence of the nobility, and created stronger, more unified nations.\":{\"type\":\"txt\",\"ans\":[\"New Monarchs\"]}}}', '[21,2,5]', 1),
(64, 'Unit 2 Terms, People, and Events ', 'lilbigman', '{\"desc\":\"Review Unit 2 stuff for Final\",\"contnt\":{\"Ancient Greek poet, often considered the \\u201cfather of Greek didactic poetry,\\u201d known for works like Theogony and Works and Days, which offer insights into early Greek mythology and daily life.\":{\"type\":\"txt\",\"ans\":[\"Hesiod\"]},\"Tyrant of Athens who, tried multiple times to assume power, and introduced significant reforms, including improving the city&#039;s infrastructure, promoting the arts, and developing a more centralized government.\":{\"type\":\"txt\",\"ans\":[\"Pisistratus\"]},\"Heavily armed foot soldiers of ancient Greek city-states, typically armed with spears, shields, and armor, who played a crucial role in Greek warfare.\":{\"type\":\"txt\",\"ans\":[\"Hoplite\"]},\"King of Macedon who united most of the Greek city-states and set the stage for his son Alexander the Great&#039;s conquests. He reformed the Macedonian army, making it one of the most powerful in the ancient world.\":{\"type\":\"txt\",\"ans\":[\"Philip II of Macedon\"]},\"Often called the &quot;Father of History,&quot; wrote Histories, a detailed record of historical events, especially the Greco-Persian Wars, and is credited with introducing historical inquiry.\":{\"type\":\"txt\",\"ans\":[\"Herodotus\"]},\"Ancient Greek historian known for his work History of the Peloponnesian War, where he provided a detailed and critical account of the conflict between Athens and Sparta, emphasizing empirical research and political analysis.\":{\"type\":\"txt\",\"ans\":[\"Thucydides\"]},\"father of geometry\":{\"type\":\"txt\",\"ans\":[\"Euclid\"]},\"Philosopher who is credited with laying the groundwork for Western philosophy. He is famous for his method of questioning (the Socratic method) and his pursuit of ethical knowledge.\":{\"type\":\"txt\",\"ans\":[\"Socrates\"]},\"Greek mathematician and geographer who calculated the Earth&#039;s circumference with remarkable accuracy and was the first to use the term &quot;geography.&quot;\":{\"type\":\"txt\",\"ans\":[\"Eratosthenes\"]},\"Ancient Greek mathematician and inventor who made fundamental contributions to geometry, calculus, and physics, including the principle of buoyancy (Archimedes&#039; Principle) and the development of the Archimedean screw.\":{\"type\":\"txt\",\"ans\":[\"Archimedes\"]},\"Roman Love poet\":{\"type\":\"txt\",\"ans\":[\"Ovid\"]},\"Roman poet, best known for his Odes, and for developing the genre of satirical poetry, often using humor and philosophical themes to critique Roman society\":{\"type\":\"txt\",\"ans\":[\"Horace\"]},\" Early Christian missionary and theologian who significantly spread Christianity throughout the Roman Empire and wrote many of the New Testament epistles, which form the theological foundation of Christianity\":{\"type\":\"txt\",\"ans\":[\"Paul of Tarsus\"]},\"Legendary founder and first king of Rome, credited with establishing the city and its first institutions, including the Senate and the Roman legions.\":{\"type\":\"txt\",\"ans\":[\"Romulus\"]},\"Roman general and politician who, along with Julius Caesar and Crassus, formed the First Triumvirate. He played a key role in the expansion of Rome, notably in the eastern Mediterranean.\":{\"type\":\"txt\",\"ans\":[\"Pompey\"]},\"Roman general and politician, part of the First Triumvirate. He was known for his immense wealth and his role in the suppression of the Spartacus slave revolt.\":{\"type\":\"txt\",\"ans\":[\"Crassus\"]},\"Roman emperor notorious for his cruelty, but also for his patronage of the arts and his ambitious building projects, including the Golden House.\":{\"type\":\"txt\",\"ans\":[\"Nero\"]},\"Elite unit of the Roman army tasked with protecting the emperor. Over time, they gained significant political influence, sometimes even determining the fate of emperors.\":{\"type\":\"txt\",\"ans\":[\"Praetorian Guard\"]},\"A Bronze Age civilization centered on the island of Crete, known for its advanced art, architecture, and maritime trade, as well as for influencing later Greek culture.\":{\"type\":\"txt\",\"ans\":[\"Minoans\"]},\"Athenian statesman and lawmaker who enacted wide-ranging political and economic reforms in Athens, laying the foundation for Athenian democracy.\":{\"type\":\"txt\",\"ans\":[\"Solon\"]},\"A form of government in which power is concentrated in the hands of a small group of people, often based on wealth, social status, or military control.\":{\"type\":\"txt\",\"ans\":[\"Oligarchy\"]},\"The central public space in ancient Greek city-states used for assemblies, markets, and various civic functions.\":{\"type\":\"txt\",\"ans\":[\"Agora\"]},\"A fortified hilltop in ancient Greek cities, especially in Athens, where important temples and public buildings were constructed, most notably the Parthenon.\":{\"type\":\"txt\",\"ans\":[\"Acropolis\"]},\"Greek playwright known for writing Oedipus Rex and Antigone, two of the most famous Greek tragedies, which have had a lasting influence on Western drama.\":{\"type\":\"txt\",\"ans\":[\"Sophocles\"]},\"Greek playwright and poet, known for developing New Comedy, a genre that focused on domestic and social themes, influencing later playwrights like Plautus and Terence.\":{\"type\":\"txt\",\"ans\":[\"Menander\"]},\"Philosopher and founder of the Academy in Athens, one of the first institutions of higher learning in the Western world. His works, including The Republic, have had a profound impact on philosophy, politics, and education.\":{\"type\":\"txt\",\"ans\":[\"Plato\"]},\"Greek astronomer who proposed the heliocentric model of the solar system, suggesting that the Earth orbits the Sun, centuries before Copernicus.\":{\"type\":\"txt\",\"ans\":[\"Aristarchus\"]},\"A philosophical system founded by Epicurus, which advocates for the pursuit of pleasure and happiness through simple living, friendship, and the avoidance of pain.\":{\"type\":\"txt\",\"ans\":[\"Epicureanism\"]},\"Roman statesman, orator, and philosopher, known for his speeches and writings on ethics, politics, and law. His works influenced the development of Roman law and Western thought.\":{\"type\":\"txt\",\"ans\":[\"Cicero\"]},\"Roman emperor who made Christianity the official religion of the Roman Empire and passed laws to suppress paganism.\":{\"type\":\"txt\",\"ans\":[\"Theodosius I\"]},\"Carthaginian general renowned for leading his forces, including war elephants, across the Alps to invade Italy during the Second Punic War, securing major victories over the Romans.\":{\"type\":\"txt\",\"ans\":[\"Hannibal Barca\"]},\"Religious leader and central figure of Christianity, whose teachings on love, forgiveness, and salvation became the foundation of the Christian faith.\":{\"type\":\"txt\",\"ans\":[\"Jesus of Nazareth\"]},\"The aristocratic class in ancient Rome, holding most of the political power and land, in contrast to the lower plebeian class.\":{\"type\":\"txt\",\"ans\":[\"Patricians\"]},\"Roman general and dictator who expanded Rome&#039;s territories through military conquest, initiated key reforms, and played a critical role in the fall of the Roman Republic.\":{\"type\":\"txt\",\"ans\":[\"Julius Caesar\"]},\"Roman general and politician, known for his role in the transformation of the Roman Republic into the Roman Empire and his famous affair with Cleopatra.\":{\"type\":\"txt\",\"ans\":[\"Marc Antony\"]},\"Roman emperor and Stoic philosopher, best known for his Meditations, a series of personal writings on Stoic philosophy and leadership.\":{\"type\":\"txt\",\"ans\":[\"Marcus Aurelius\"]},\"An ancient Greek civilization known for its palatial states, military prowess, and involvement in the Trojan War, later influencing classical Greek culture.\":{\"type\":\"txt\",\"ans\":[\"Mycenaeans\"]},\"Athenian statesman who introduced democratic reforms, including the reorganization of the citizenry into ten tribes, creating the foundations for Athenian democracy.\":{\"type\":\"txt\",\"ans\":[\"Cleisthenes\"]},\"A form of government where a single ruler holds absolute power, often obtained through unconstitutional means, as opposed to a legitimate monarchy or democracy.\":{\"type\":\"txt\",\"ans\":[\"Tyranny\"]},\"Most importantly died by a turtle. Greek playwright, often called the \\u201cfather of tragedy,\\u201d who introduced the second actor in drama and wrote Oresteia, a trilogy that is a key work in Western literature\":{\"type\":\"txt\",\"ans\":[\"Aeschylus\"]},\"Athenian statesman who led Athens during its Golden Age, promoting democracy, arts, and philosophy, and overseeing the construction of the Parthenon.\":{\"type\":\"txt\",\"ans\":[\"Pericles\"]},\"Greek philosopher and student of Plato, who made contributions to nearly every area of knowledge, including logic, biology, ethics, and politics, and founded the Lyceum.\":{\"type\":\"txt\",\"ans\":[\"Aristotle\"]},\"Often regarded as the \\u201cfather of medicine,\\u201d he established the ethical and professional standards for physicians, and the Hippocratic Oath is still a foundational text in medical ethics.\":{\"type\":\"txt\",\"ans\":[\"Hippocrates\"]},\"A philosophy founded by Zeno of Citium that emphasizes virtue, self-control, and rationality, aiming to live in harmony with nature and to overcome destructive emotions.\":{\"type\":\"txt\",\"ans\":[\"Stoicism\"]},\"Recorded the hisotry of rome\":{\"type\":\"txt\",\"ans\":[\"Livy\"]},\"Roman emperor who converted to Christianity\":{\"type\":\"txt\",\"ans\":[\"Constantine\"]}}}', '[21,2,22,20]', 1),
(65, 'British Lit Fall Final', 'ChangeYourName', '{\"desc\":\"\",\"contnt\":{\"Historical era from 449 to 1066 in England.\":{\"type\":\"txt\",\"ans\":[\"Anglo-Saxon Period\"]},\"Indigenous Celtic people of ancient Britain.\":{\"type\":\"mc\",\"op\":[\"Britons\",\"Angles\",\"Saxons\",\"Normans\"],\"ans\":[0]},\"Ancient civilization that conquered Britain.\":{\"type\":\"txt\",\"ans\":[\"Rome\"]},\"Early English historian and monk, author of &#039;Ecclesiastical History&#039;.\":{\"type\":\"txt\",\"ans\":[\"Bede\"]},\"King of Wessex, known for defending against Vikings.\":{\"type\":\"txt\",\"ans\":[\"Alfred the Great\"]},\"Missionary who converted Anglo-Saxons to Christianity.\":{\"type\":\"txt\",\"ans\":[\"St. Augustine\"]},\"Anglo-Saxon poet or storyteller.\":{\"type\":\"txt\",\"ans\":[\"Scop\"]},\"Compound metaphorical phrase used in Old English poetry.\":{\"type\":\"txt\",\"ans\":[\"Kenning\"]},\"Repetition of consonant sounds at the beginning of words.\":{\"type\":\"txt\",\"ans\":[\"Alliteration\"]},\"Concept of fate in Anglo-Saxon culture.\":{\"type\":\"txt\",\"ans\":[\"Wyrd\"]},\"Long narrative poem detailing heroic deeds.\":{\"type\":\"txt\",\"ans\":[\"Epic\"]},\"Poetry expressing sorrow or lamentation.\":{\"type\":\"txt\",\"ans\":[\"Elegiac\"]},\"Collection of stories by Geoffrey Chaucer.\":{\"type\":\"txt\",\"ans\":[\"The Canterbury Tales\"]},\"Social system in medieval Europe based on land ownership.\":{\"type\":\"txt\",\"ans\":[\"Feudalism\"]},\"1215 document limiting the power of the English monarchy.\":{\"type\":\"txt\",\"ans\":[\"Magna Carta\"]},\"Code of conduct associated with medieval knighthood.\":{\"type\":\"txt\",\"ans\":[\"Chivalry\"]},\"Renaissance movement emphasizing human potential and achievements.\":{\"type\":\"txt\",\"ans\":[\"Humanism\"]},\"Period during the reign of James I.\":{\"type\":\"txt\",\"ans\":[\"Jacobean Era\"]},\"Tragic play by William Shakespeare about ambition.\":{\"type\":\"txt\",\"ans\":[\"Macbeth\"]},\"Literary device addressing an absent person or concept.\":{\"type\":\"txt\",\"ans\":[\"Apostrophe\"]},\"Extended metaphor comparing two vastly different things.\":{\"type\":\"txt\",\"ans\":[\"Conceit\"]}}}', '[21,20,22,19,5]', 1),
(66, 'Unit 1 Terms, People, and Events', 'lilbigman', '{\"desc\":\"Review Unit 1 stuff for the final\",\"contnt\":{\"The cultural, social, and political heritage that emerged in Europe, influenced by Ancient Greece and Rome, and later shaped by Christianity, the Enlightenment, and the development of modern democratic principles.\":{\"type\":\"txt\",\"ans\":[\"west civ\"]},\"The earliest period of human history, also known as the Old Stone Age, when humans lived as hunter-gatherers and used primitive tools made from stone, lasting from around 2.5 million years ago to about 10,000 BCE.\":{\"type\":\"txt\",\"ans\":[\"Paleolithic Era\"]},\"A major transformation around 10,000 BCE when human societies shifted from hunting and gathering to settled farming, leading to the development of permanent settlements and the rise of agriculture.\":{\"type\":\"txt\",\"ans\":[\"Neolithic Revolution\\/Era\"]},\"An ancient region between the Tigris and Euphrates Rivers, often called the &quot;Cradle of Civilization,&quot; where early human civilizations like the Sumerians, Akkadians, Babylonians, and Assyrians developed.\":{\"type\":\"txt\",\"ans\":[\"Mesopotamia\"]},\"Two major rivers in Mesopotamia that were crucial for the development of early civilizations by providing water for agriculture and enabling trade and transport.\":{\"type\":\"txt\",\"ans\":[\"Tigris River and Euphrates River\"]},\"One of the first civilizations in Mesopotamia, known for their invention of cuneiform writing and the development of city-states.\":{\"type\":\"txt\",\"ans\":[\"Sumerian\"]},\"A system of writing developed by the Sumerians around 3500 BCE, using wedge-shaped marks on clay tablets, considered one of the earliest forms of writing.\":{\"type\":\"txt\",\"ans\":[\"Cuneiform\"]},\"A massive, terraced step pyramid structure built in ancient Mesopotamia, typically as a temple for worshiping gods.\":{\"type\":\"txt\",\"ans\":[\"Ziggurat\"]},\"An epic poem from Mesopotamia, one of the earliest works of literary fiction, telling the story of King Gilgamesh and his quest for immortality.\":{\"type\":\"txt\",\"ans\":[\"Epic of Gilgamesh\"]},\"Founder of the Akkadian Empire around 2334 BCE, often regarded as the first ruler to unite the city-states of Mesopotamia under a single rule.\":{\"type\":\"txt\",\"ans\":[\"Sargon\"]},\" An ancient city-state in Mesopotamia, later the capital of the Babylonian Empire, known for its advancements in law, astronomy, and architecture.\":{\"type\":\"txt\",\"ans\":[\"Babylon\"]},\"King of Babylon from 1792 to 1750 BCE, famous for creating one of the earliest and most complete written legal codes, the Code of Hammurabi.\":{\"type\":\"txt\",\"ans\":[\"Hammurabi\"]},\"A set of laws established by Hammurabi, one of the earliest written legal codes in history, known for its strict justice system and the concept of &quot;an eye for an eye.&quot;\":{\"type\":\"txt\",\"ans\":[\"Code of\\u00a0Hammurabi\"]},\"A crescent-shaped region of the Middle East, including parts of Mesopotamia, Egypt, and the Levant, known for its fertile land and the early development of agriculture and civilization.\":{\"type\":\"txt\",\"ans\":[\"Fertile Crescent\"]},\"A way of life based on raising livestock such as cattle, sheep, and goats, practiced by nomadic and semi-nomadic peoples.\":{\"type\":\"txt\",\"ans\":[\"Pastoralism\"]},\"A social system in which men hold primary power and authority over political leadership, moral authority, and property.\":{\"type\":\"txt\",\"ans\":[\"Patriarchy\"]},\"A period in human history (approximately 3300\\u20131200 BCE) marked by the use of bronze tools and weapons, the rise of cities, and the development of trade networks\":{\"type\":\"txt\",\"ans\":[\"Bronze Age\"]},\"The period following the Bronze Age, beginning around 1200 BCE, characterized by the use of iron tools and weapons, and the development of more advanced cultures and societies.\":{\"type\":\"txt\",\"ans\":[\"\"]}}}', '[21,14,4]', 1),
(67, 'Unit 3 Terms, People, and Events', 'lilbigman', '{\"desc\":\"Review Unit 3 stuff for the final\",\"contnt\":{\"Pope from 590 to 604, influential in strengthening the papacy. Promoted missionary work, notably in England, and helped establish the Church&#039;s authority over secular rulers. Introduced reforms that shaped the administration of the Church and emphasized the importance of pastoral care.\":{\"type\":\"txt\",\"ans\":[\"Gregory I (Gregory the Great)\"]},\"King of France from 1180 to 1223, known for expanding royal power. Successfully challenged the English crown for control of French territories, notably during the wars against King John. Strengthened the monarchy and laid the groundwork for the centralized French state.\":{\"type\":\"txt\",\"ans\":[\"Philip II Augustus\"]},\"A physical object of religious significance, often a body part or personal item of a saint.\":{\"type\":\"txt\",\"ans\":[\"Relic\"]},\"Land retained by a lord for their own use, separate from the lands held by vassals or peasants.\":{\"type\":\"txt\",\"ans\":[\"Demesne\"]},\"Clergy members who did not belong to a religious order and were typically involved in the administration of dioceses.\":{\"type\":\"txt\",\"ans\":[\"Secular Clergy\"]},\"Clergy who live under a specific religious rule, such as monks and nuns.\":{\"type\":\"txt\",\"ans\":[\"Regular Clergy\"]},\"The Eastern Roman Empire, continuing after the fall of the Western Roman Empire, centered in Constantinople.\":{\"type\":\"txt\",\"ans\":[\"Byzantine Empire\"]},\"A codification of Roman law commissioned by Emperor Justinian I in the 6th century.\":{\"type\":\"txt\",\"ans\":[\"Code of\\u00a0 Justinian\"]},\"A revival of art, culture, and learning under Charlemagne in the 8th and 9th centuries\":{\"type\":\"txt\",\"ans\":[\"Carolingian Renaissance\"]},\"A cultural and artistic revival in Northumbria during the 7th and 8th centuries.\":{\"type\":\"txt\",\"ans\":[\"Northumbrian Renaissance\"]},\"A Dominican theologian and philosopher, author of &quot;Summa Theologica.&quot;\":{\"type\":\"txt\",\"ans\":[\"Thomas Aquinas\"]},\"A series of religious wars initiated by European Christians to reclaim the Holy Land from Muslim control.\":{\"type\":\"txt\",\"ans\":[\"Crusades\"]},\"A widespread famine caused by climate change, poor harvests, and economic distress.\":{\"type\":\"txt\",\"ans\":[\"Great Famine\"]},\"Muslim military leader known for his role in the Crusades, particularly during the Third Crusade.\":{\"type\":\"txt\",\"ans\":[\"Saladin\"]},\"Early Christian scholar and translator, known for the Vulgate translation of the Bible. His translation made the Scriptures more accessible to the Latin-speaking Church.\":{\"type\":\"txt\",\"ans\":[\"Jerome\"]},\"A parcel of land granted to a vassal by a lord in exchange for military service.\":{\"type\":\"txt\",\"ans\":[\"Fief\"]},\"A senior ecclesiastical leader in charge of a diocese, overseeing priests and the administration of the Church.\":{\"type\":\"txt\",\"ans\":[\"Bishop\"]},\"The office of the Pope, the leader of the Roman Catholic Church.\":{\"type\":\"txt\",\"ans\":[\"Papacy\"]},\"A religious way of life characterized by asceticism and communal living, often in monasteries.\":{\"type\":\"txt\",\"ans\":[\"Monasticism\"]},\"A realm established by the Franks, notably under Charlemagne, in what is now France and Germany.\":{\"type\":\"txt\",\"ans\":[\"Frankish Empire\"]},\"The first royal dynasty of the Franks, ruling from the 5th to the 8th century.\":{\"type\":\"txt\",\"ans\":[\"Merovingian Dynasty\"]},\"A dynasty that rose to power in the 8th century, founded by Charles Martel and associated with Charlemagne.\":{\"type\":\"txt\",\"ans\":[\"Carolingian Dynasty\"]},\"His reign marked a high point in the Carolingian Renaissance, promoting culture, education, and administration.King of the Franks and Emperor of the Carolingian Empire (c. 742-814).United much of Western Europe and was crowned Emperor by the Pope in 800, symbolizing the union of church and state.\\u00a0His reign marked a high point in the Carolingian Renaissance, promoting culture, education, and administration.\\u00a0\":{\"type\":\"txt\",\"ans\":[\"Charlemagne\"]},\" An architectural style that flourished in Europe from the 12th to the 16th centuries, characterized by pointed arches, ribbed vaults, and flying buttresses.\":{\"type\":\"txt\",\"ans\":[\"Gothic Architecture\"]},\" Duke of Normandy who invaded England in 1066 and became its king.\":{\"type\":\"txt\",\"ans\":[\"William I \\u201cthe Conqueror\\u201d\"]},\"A hierarchical system of land ownership and duties where lords granted land (fiefs) to vassals in exchange for military service.\":{\"type\":\"txt\",\"ans\":[\"Feudalism\"]},\"An economic system in which a lord&#039;s manor was the basic unit of agricultural production and social organization.\":{\"type\":\"txt\",\"ans\":[\"Manorialism\"]},\"A district under the pastoral care of a bishop in the Christian Church\":{\"type\":\"txt\",\"ans\":[\"Diocese\"]},\"Christian monk who founded the Benedictine monastic order and wrote the Rule of St. Benedict\":{\"type\":\"txt\",\"ans\":[\"St. Benedict\"]},\" Early Christian theologian and philosopher whose works shaped Western Christianity.\":{\"type\":\"txt\",\"ans\":[\"Augustine of Hippo\"]},\"The Muslim-ruled territories in the Iberian Peninsula during the Middle Ages.\":{\"type\":\"txt\",\"ans\":[\"Al-Andalus\"]},\"The founder of Islam and considered the final prophet in Islamic tradition.\":{\"type\":\"txt\",\"ans\":[\"Muhammad\"]},\"The foundational acts of worship in Islam, including the declaration of faith, prayer, fasting, almsgiving, and pilgrimage.\":{\"type\":\"txt\",\"ans\":[\"Five Pillars of Islam\"]},\"Norse seafarers known for their raids, exploration, and trade across Europe from the late 8th to the 11th centuries.\":{\"type\":\"txt\",\"ans\":[\"Vikings\"]},\" Institutions of higher learning that emerged in the 12th century, focusing on theology, law, medicine, and the arts.\":{\"type\":\"txt\",\"ans\":[\"Universities\"]},\"A devastating pandemic caused by the bubonic plague, resulting in the death of millions across Europe.\":{\"type\":\"txt\",\"ans\":[\"Black Death\"]},\"A series of conflicts between England and France over territorial claims and the French crown.\":{\"type\":\"txt\",\"ans\":[\"Hundred Years War\"]}}}', '[21,2,14,5]', 1),
(68, 'The Vocabulary of Literature (8th Grade)', 'FiestaHibiscus', '{\"desc\":\"All the vocab words for 8th Grade (in progress)\",\"contnt\":{\"latter\":{\"type\":\"txt\",\"ans\":[\"the second\"]},\"dejected\":{\"type\":\"txt\",\"ans\":[\"in low spirits\"]},\"despondent\":{\"type\":\"txt\",\"ans\":[\"disheartened\"]},\"rebuke\":{\"type\":\"txt\",\"ans\":[\"a sharp criticism\"]},\"aloof\":{\"type\":\"txt\",\"ans\":[\"unfriendly\"]},\"portent\":{\"type\":\"txt\",\"ans\":[\"an omen\"]},\"resolute\":{\"type\":\"txt\",\"ans\":[\"determined\"]},\"countenance\":{\"type\":\"txt\",\"ans\":[\"facial expression\"]},\"manifest\":{\"type\":\"txt\",\"ans\":[\"obvious\"]},\"languor\":{\"type\":\"txt\",\"ans\":[\"weakness\"]},\"placate\":{\"type\":\"txt\",\"ans\":[\"to appease\"]},\"derision\":{\"type\":\"txt\",\"ans\":[\"ridicule\"]},\"vivacious\":{\"type\":\"txt\",\"ans\":[\"full of life\"]},\"procure\":{\"type\":\"txt\",\"ans\":[\"to acquire\"]},\"retort\":{\"type\":\"txt\",\"ans\":[\"a quick, clever reply\"]},\"prodigious\":{\"type\":\"txt\",\"ans\":[\"huge\"]},\"writhe\":{\"type\":\"txt\",\"ans\":[\"to twist, to squirm\"]},\"dissipate\":{\"type\":\"txt\",\"ans\":[\"to disperse\"]},\"benevolent\":{\"type\":\"txt\",\"ans\":[\"charitable\"]},\"profuse\":{\"type\":\"txt\",\"ans\":[\"abundant\"]},\"prostrate\":{\"type\":\"txt\",\"ans\":[\"lying flat\"]},\"abashed\":{\"type\":\"txt\",\"ans\":[\"embarrassed\"]},\"serene\":{\"type\":\"txt\",\"ans\":[\"calm\"]},\"plaintive\":{\"type\":\"txt\",\"ans\":[\"mournful\"]},\"melancholy\":{\"type\":\"txt\",\"ans\":[\"sadness\"]},\"fervor\":{\"type\":\"txt\",\"ans\":[\"passion\"]},\"conjecture\":{\"type\":\"txt\",\"ans\":[\"a guess\"]},\"perplex\":{\"type\":\"txt\",\"ans\":[\"to confuse\"]},\"somber\":{\"type\":\"txt\",\"ans\":[\"gloomy\"]},\"billow\":{\"type\":\"txt\",\"ans\":[\"a wave\"]},\"myriad\":{\"type\":\"txt\",\"ans\":[\"countless\"]},\"reprove\":{\"type\":\"txt\",\"ans\":[\"to reprimand\"]},\"singular\":{\"type\":\"txt\",\"ans\":[\"unique\"]},\"audible\":{\"type\":\"txt\",\"ans\":[\"able to be heard\"]},\"amiable\":{\"type\":\"txt\",\"ans\":[\"friendly\"]},\"fain\":{\"type\":\"txt\",\"ans\":[\"pleased\"]},\"entreat\":{\"type\":\"txt\",\"ans\":[\"to ask earnestly\"]},\"conjure\":{\"type\":\"txt\",\"ans\":[\"to summon\"]},\"importune\":{\"type\":\"txt\",\"ans\":[\"to pester\"]},\"magnanimous\":{\"type\":\"txt\",\"ans\":[\"generous\"]},\"expedient\":{\"type\":\"txt\",\"ans\":[\"a convenient means\"]},\"vex\":{\"type\":\"txt\",\"ans\":[\"to irritate\"]},\"incredulous\":{\"type\":\"txt\",\"ans\":[\"skeptical\"]},\"clamor\":{\"type\":\"txt\",\"ans\":[\"outcry\"]},\"reproach\":{\"type\":\"txt\",\"ans\":[\"accuse, blame, rebuke\"]},\"expostulate\":{\"type\":\"txt\",\"ans\":[\"to object earnestly\"]},\"placid\":{\"type\":\"txt\",\"ans\":[\"calm\"]},\"deprecate\":{\"type\":\"txt\",\"ans\":[\"to deplore\"]},\"demure\":{\"type\":\"txt\",\"ans\":[\"modest and shy\"]},\"pensive\":{\"type\":\"txt\",\"ans\":[\"thoughtful\"]},\"injunction\":{\"type\":\"txt\",\"ans\":[\"a command\"]},\"eddy\":{\"type\":\"txt\",\"ans\":[\"a swirl or whirlpool\"]},\"decorum\":{\"type\":\"txt\",\"ans\":[\"proper behavior\"]},\"oblique\":{\"type\":\"txt\",\"ans\":[\"indirect or slanting\"]},\"venerate\":{\"type\":\"txt\",\"ans\":[\"to respect\"]},\"din\":{\"type\":\"txt\",\"ans\":[\"a racket\"]},\"peremptory\":{\"type\":\"txt\",\"ans\":[\"dictatorial\"]},\"wan\":{\"type\":\"txt\",\"ans\":[\"pallid or weak\"]},\"phenomenon\":{\"type\":\"txt\",\"ans\":[\"an unusual occurrence\"]},\"morose\":{\"type\":\"txt\",\"ans\":[\"sullen\"]},\"droll\":{\"type\":\"txt\",\"ans\":[\"amusing\"]},\"confound\":{\"type\":\"txt\",\"ans\":[\"to perplex\"]},\"wince\":{\"type\":\"txt\",\"ans\":[\"to shrink involuntarily\"]},\"diffidence\":{\"type\":\"txt\",\"ans\":[\"lack of confidence\"]},\"jovial\":{\"type\":\"txt\",\"ans\":[\"cheerful\"]},\"listless\":{\"type\":\"txt\",\"ans\":[\"uninterested\"]},\"sallow\":{\"type\":\"txt\",\"ans\":[\"sickly yellow\"]},\"grimace\":{\"type\":\"txt\",\"ans\":[\"a sharp expression\"]},\"evince\":{\"type\":\"txt\",\"ans\":[\"to show\"]},\"exquisite\":{\"type\":\"txt\",\"ans\":[\"beautifully made\"]},\"acute\":{\"type\":\"txt\",\"ans\":[\"sharp\"]},\"condescend\":{\"type\":\"txt\",\"ans\":[\"to patronize\"]},\"grotesque\":{\"type\":\"txt\",\"ans\":[\"distorted\"]},\"allude\":{\"type\":\"txt\",\"ans\":[\"indirectly refer to\"]},\"ostentatious\":{\"type\":\"txt\",\"ans\":[\"showy\"]},\"inexorable\":{\"type\":\"txt\",\"ans\":[\"inevitable\"]},\"indolent\":{\"type\":\"txt\",\"ans\":[\"lazy\"]},\"doleful\":{\"type\":\"txt\",\"ans\":[\"mournful\"]},\"alacrity\":{\"type\":\"txt\",\"ans\":[\"eagerness\"]}}}', '[11,2,21,14,1,22]', 1),
(69, 'Brit Lit Final P.1', 'lilbigman', '{\"desc\":\"Review for the English final\",\"contnt\":{\"n Old English epic poem, considered one of the most important works of Anglo-Saxon literature\":{\"type\":\"txt\",\"ans\":[\"Beowulf\"]},\"The hero who battles Grendel, Grendel&#039;s Mother, and a dragon\":{\"type\":\"txt\",\"ans\":[\"Beowulf\"]},\"Character in Beowulf who represents the exact of Anglo-Saxon values\":{\"type\":\"txt\",\"ans\":[\"Grendel\"]},\"A poetic verse addressing topics such as loss, death, love, and war\":{\"type\":\"txt\",\"ans\":[\"Elegaic\"]},\"Something that goes like ... of ...\":{\"type\":\"txt\",\"ans\":[\"Kenning\"]},\"A lyrical poem about an exiled man finding his purpose\":{\"type\":\"txt\",\"ans\":[\"the seafarer\"]},\"A character in the Canterbury tales who is supposed loyal and modest and is anything but that\":{\"type\":\"txt\",\"ans\":[\"Wife of Bath\"]},\"A character in the Canterbury tales who is humble, modest, fair, and perfect\":{\"type\":\"txt\",\"ans\":[\"The parson\"]},\"A character in the Canterbury tales who is supposed to be humble and concerned for other peoples soul but instead cares about money and is selfish\":{\"type\":\"txt\",\"ans\":[\"The pardoner\"]},\"The father of english poetry and fiction. Wrote the Canterbury tales. Fascinated by Humans.\":{\"type\":\"txt\",\"ans\":[\"Geoffrey Chaucer\"]},\"A character in the Canterbury tales who is perfect and courageous\\u00a0\":{\"type\":\"txt\",\"ans\":[\"The Knight\"]},\"A character in the Canterbury tales who is supposed to modest and chaste, instead is very polite and has little satire\":{\"type\":\"txt\",\"ans\":[\"The Prioress\"]},\"A character in the Canterbury tales who is supposed to be modest and has self-discipline but instead is fat and owns many horses.\":{\"type\":\"txt\",\"ans\":[\"The Monk\"]},\"A brief statement of a general truth\":{\"type\":\"txt\",\"ans\":[\"Maxim\"]},\"A short story used to express a moral point\":{\"type\":\"txt\",\"ans\":[\"Exemplum\"]},\"English writer who fought in the Hundred Yrs War and had serious approach to the world of medieval romance with knights and damsels in distress. Also wrote Morte D&#039; Arthur\":{\"type\":\"txt\",\"ans\":[\"Thomas Malory\"]},\"Battle between York and Lancaster\\u00a0\":{\"type\":\"txt\",\"ans\":[\"War of the Roses\"]},\"Nurtured the renaissance\":{\"type\":\"txt\",\"ans\":[\"Tudor Dynasty\"]},\"Wrote Utopia\":{\"type\":\"txt\",\"ans\":[\"Thomas More\"]},\"Established Tudor Dynasty\":{\"type\":\"txt\",\"ans\":[\"Henry VIII\"]},\"Established first public theatre\":{\"type\":\"txt\",\"ans\":[\"Elizabeth I\"]},\"The year that the Spanish armada was sent\":{\"type\":\"txt\",\"ans\":[\"1588\"]},\"clever or cunning devices\":{\"type\":\"txt\",\"ans\":[\"Artifice\"]},\"a hierarchical structure of all matter and life\":{\"type\":\"txt\",\"ans\":[\"Great chain of being\"]},\"Holds that there is a deep, hidden relationship between all things, with higher and lower realms of reality being reflections of each other\":{\"type\":\"txt\",\"ans\":[\"Doctrine of Correspondence\"]},\"The period of English history and culture during the reign of King James I of England marked by the\\u00a0transition from stability to turmoil\":{\"type\":\"txt\",\"ans\":[\"Jacobean Era\"]},\"Made the heliocentric theory and thought the sun was at the center of universe\":{\"type\":\"txt\",\"ans\":[\"Copernicus and Galileo\"]},\"Sought to reform the Catholic Church\":{\"type\":\"txt\",\"ans\":[\"Charles I and the puritan movement\"]},\"The year in which Charles I was executed and the Commonwealth was made\":{\"type\":\"txt\",\"ans\":[\"1649 (January 30)\"]},\"Became the Lord Protector of the Commonwealth (1653-1658), effectively serving as the head of state. During his rule, he implemented Puritan reforms and a strict moral code, while also maintaining a strong military presence. His reign marked a period of authoritarian rule under the guise of republicanism, which led to both reform and dissent.\":{\"type\":\"txt\",\"ans\":[\"Oliver Cromwell\"]},\"Returned England back to a monarchy\":{\"type\":\"txt\",\"ans\":[\"Charles II\"]},\"English Civil War\":{\"type\":\"txt\",\"ans\":[\"17th Century\"]},\"A drama\\u00a0 written by Shakespeare\":{\"type\":\"txt\",\"ans\":[\"Macbeth\"]},\"Known for its intellectual rigor, conceits, and philosophical themes\":{\"type\":\"txt\",\"ans\":[\"Metaphysical poetry\"]},\"To poetry that is influenced by the works of ancient Greek and Roman poets.\\u00a0This form emphasizes order, balance, and rationality\":{\"type\":\"txt\",\"ans\":[\"Classical poetry\"]},\"Royalist, Light-hearted Style\":{\"type\":\"txt\",\"ans\":[\"Cavalier poetry\"]},\"Made king James I\":{\"type\":\"txt\",\"ans\":[\"King James bible\"]},\"Epic Poet of the English Renaissance\":{\"type\":\"txt\",\"ans\":[\"John Milton\"]}}}', '[1,21,2,20,14]', 1),
(70, 'Brit Lit Final P.2', 'lilbigman', '{\"desc\":\"Review for the Brit. Lit Final\",\"contnt\":{\"What battle in 1066 brought a Norman king to the English throne?\":{\"type\":\"mc\",\"op\":[\"a. Maldon\",\"b. Hastings\",\"c. Winchester\",\"d. Normandy\"],\"ans\":[1]},\"The Normans came from a region in present-day\":{\"type\":\"mc\",\"op\":[\"a.\\u00a0 France\",\"b.\\u00a0 Belgium\",\"c. Denmark\",\"d. Norway\"],\"ans\":[0]},\"In the centuries following this final conquest of England, the Norman and Saxon elements\":{\"type\":\"mc\",\"op\":[\"a. remained at war\",\"b. fused to form a national character servant\",\"c. stubbornly refused to be reconciled\",\"d. continued to remain master\"],\"ans\":[2]},\"The term we use to identify the social system of medieval England and Europe\":{\"type\":\"mc\",\"op\":[\"a. chivalry\",\"b. feudalism\",\"c. monasticism\",\"d. socialism\"],\"ans\":[1]},\"An important characteristic of that social system was its\":{\"type\":\"mc\",\"op\":[\"a. religious and political freedom\",\"b. surprising personal freedom\",\"c. considerable social mobility\\u00a0\",\"d. fixed class positions\"],\"ans\":[3]},\"The Crusades resulted in all of the following EXCEPT\":{\"type\":\"mc\",\"op\":[\"a. the introduction of advanced Arabic culture to Europe\",\"b. the conversion of many Christians to Islam\",\"c. the development of knightly chivalry\\u00a0\",\"d. a broadening of Europe&#039;s commercial horizons\"],\"ans\":[1]},\"The Magna Carta is important in that it eventually established\\u00a0\":{\"type\":\"mc\",\"op\":[\"a. the right of English men to own property\",\"b. rules for the important wool trade\",\"c. medieval concepts of chivalry\\u00a0\",\"d. the principle of one law for all\\u00a0\"],\"ans\":[3]},\"The English Wars of the Roses basically were which of the following?\":{\"type\":\"mc\",\"op\":[\"a. conflicts over England&#039;s Norman holdings\\u00a0\",\"b. wars between the houses of York and Lancaster\",\"c. border wars between Scotland and England\\u00a0\",\"d. Wars between the houses of York and Windsor\"],\"ans\":[1]},\"The first writer to achieve real greatness in English Lit. was\\u00a0\":{\"type\":\"mc\",\"op\":[\"a. Sir Thomas Malory\\u00a0\",\"b. John Wycliff\",\"c. Geoffrey Chaucer\\u00a0\",\"d. Caedmon\"],\"ans\":[2]},\"The ballads of the fourteenth and fifteenth centuries came from\":{\"type\":\"mc\",\"op\":[\"a. returning crusaders\\u00a0\",\"b. Chaucer and other writers\\u00a0\",\"c. anonymous, common people\",\"d. French romances\"],\"ans\":[2]},\"A combination of qualities including courage, honer, and justice\":{\"type\":\"txt\",\"ans\":[\"Chivalry\"]},\"Idealizes chivalry, holds women in high regard, has a noble hero\":{\"type\":\"txt\",\"ans\":[\"medieval romance\"]},\"fictitious accounts of life and miracles, somewhat comical\":{\"type\":\"txt\",\"ans\":[\"miracle plays\"]},\"presents lessons about good conduct and morals\":{\"type\":\"txt\",\"ans\":[\"morality plays\"]},\"the practice of assessing a person&#039;s character from their appearance\":{\"type\":\"txt\",\"ans\":[\"physiognomy\"]},\"archbishop of england\":{\"type\":\"txt\",\"ans\":[\"Thomas a becket\"]},\"an inventory of property throughout England that was drawn up at william the conquerors demand\":{\"type\":\"txt\",\"ans\":[\"Doomsday Book\"]},\"gives first born son father&#039;s property and titles upon death\":{\"type\":\"txt\",\"ans\":[\"law of primogeniture\"]},\"a contract saying that the king cannot levy the taxes without consent of barons\":{\"type\":\"txt\",\"ans\":[\"magna carta\"]},\"Very little is known about the Britons,\\u00a0a Celtic people who were early inhabitants of Britain. They were conquered by the _____ in the first century A.D. and became a part of the ___ Empire.\":{\"type\":\"txt\",\"ans\":[\"Romans, Roman\"]},\"According to tradition, it was in ____ that the first band of people from the great North German plain crossed the North Sea to Britain and settled in what is now the county of Kent the Jutes Angles and Saxons.\":{\"type\":\"txt\",\"ans\":[\"449\"]},\"These Germanic tribes brought with them a common language, the ancestor of our present-day English, which we call ___or ____.\":{\"type\":\"txt\",\"ans\":[\"Old English, Anglo-Saxon\"]},\" Anglo-Saxon England was born in warfare, remained an essentially military society, and came to an end in _____ because of the superior strategy of another military- the _____\":{\"type\":\"txt\",\"ans\":[\"1066, Normans\"]},\"The Anglo-Saxons shared a heroic ideal and a set of traditional heroes. They admired men of outstanding ___. ______ to the leader of the tribe and fierce personal valor were considered necessary to the survival of their tribe or people.\":{\"type\":\"txt\",\"ans\":[\"courage, Loyalty\"]},\"The ruler was supposed to be ______ to those who were loyal.\":{\"type\":\"txt\",\"ans\":[\"Generous\"]},\"The spread of Christianity was strengthened by missionaries from the Continent. The most famous of these, _______ came in 597 and established a monastery at Canterbury. He became the first archbishop of Canterbury.\":{\"type\":\"txt\",\"ans\":[\"St. Augustine\"]},\"The earlier prose writers and chroniclers among the Anglo-Saxon churchmen also wrote in Latin. The greatest of these was known as the _________\\u00a0 the most learned and industrious writer of the whole period, author of A History of the English Church and People\":{\"type\":\"txt\",\"ans\":[\"Venerable Bede\"]},\"_________ promoted use of written English and was responsible for the initiation of the ______ , the first historical record to be kept in English.\\u00a0\":{\"type\":\"txt\",\"ans\":[\"Alfred the Great, Anglo-Saxon chronicle\"]},\"The two most important traditions of Anglo-Saxon poetry were the ______ and _______ traditions.\\u00a0\":{\"type\":\"txt\",\"ans\":[\"Heroic, Elegaic\"]},\"The period of European history and culture traditionally known as the _______began in Italy during the fourteenth century and extended, in England at least, past the middle of the seventeenth century.\":{\"type\":\"txt\",\"ans\":[\"Renaissance\"]},\"This period revitalized interest in\\u00a0 ___ and ______ civilizations.\":{\"type\":\"txt\",\"ans\":[\"Art, Learning\"]},\"Scholars and educators who called themselves ________ began to emphasize the capacities of the human mind and the achievements of human culture, in contrast to the medieval emphasis on God and contempt for the things of the world.\":{\"type\":\"txt\",\"ans\":[\"Philosophers\"]},\"During the fifteenth century, [the great period in Italy did not expand to England because of the] terrible internal turmoil and instability [caused by] _______\\u00a0 battle for the throne between the Yorks and Lancasters.\\u00a0\":{\"type\":\"txt\",\"ans\":[\"War of Roses\"]},\"__________ (author) _______may be thought of as the first literary masterpiece of the [English period of literary and artistic rebirth).\\u00a0\":{\"type\":\"txt\",\"ans\":[\"Thomas More, Utopia\"]},\"[T]he movement of religious protest against the authority and corruption of the Roman Catholic Church had been simmering for several years. This movement, known as the _______ was fiercely accelerated [with the actions of Martin Luther]\":{\"type\":\"txt\",\"ans\":[\"Protestant Reformation\"]},\"On the death of Henry VIII... ________ [took the throne and was) ideally equipped to encourage those literary and artistic developments that would finally allow [literary and artistic development to grow and flourish).\":{\"type\":\"txt\",\"ans\":[\"Elizabeth 1\"]},\"The greatest and most distinctive achievement of Elizabethan literature is in _____\":{\"type\":\"txt\",\"ans\":[\"Drama\"]},\"The most striking feature of the Elizabethan artistic taste is a delight in elaborate pattern and complicated ornamentation known as ____\":{\"type\":\"txt\",\"ans\":[\"Artifice\"]},\"Elizabethans saw the world as a vast, unified, hierarchical order, or _______ [ in which every existing being or thing was ranked within a category along a vertical spectrum).\\u00a0\\u00a0\":{\"type\":\"txt\",\"ans\":[\"Great Chain of Being\"]},\"In ________, each member of a group corresponded to same-ranking members of other groups. Thus gold was analogous to oak. Thus Elizabethan writers had at hand a wealth of symbolic relationships, references, and allusions\":{\"type\":\"txt\",\"ans\":[\"Doctrine of Correspondence\"]},\" During the Jacobean era, ______ ruled his\\/her kingdom of Scotland together with thatof England until 1625.\\u00a0\\u00a0\":{\"type\":\"txt\",\"ans\":[\"James I\"]},\"_______ took the power of the government into his own hands and established what he called the Protectorate[, a military dictatorship that did not endure very long).\":{\"type\":\"txt\",\"ans\":[\"Oliver Cromwell\"]},\"By 1660, the English people had had enough of the _______ rule, and ______returned [to the throne) in what we call the _____\\u00a0\":{\"type\":\"txt\",\"ans\":[\"Commonwealth, Charles II, Restoration\"]},\"______\\u00a0poetry extends the Elizabethan love of intricate verbal [construction] and feeling for dramatic voice and situation... [it is more argumentative in tone, its language is more colloquial; its meter is usually varied...if often depends on the combination of dissimilar images].\":{\"type\":\"txt\",\"ans\":[\"\\u00a0Metaphysical\"]},\"The second major style or approach (to poetry in the seventeenth century) was classical and conservative, [an example of which is] ____, [the poems of this variety] are light, witty, and elegant, yet they retain [an emphasis on fineness and precision of form].\":{\"type\":\"txt\",\"ans\":[\"Cavalier poetry\"]}}}', '[21,1,14,5]', 1),
(71, 'Brit Lit. Final P.3', 'lilbigman', '{\"desc\":\"Review for English Final\",\"contnt\":{\"an old English poet or bard\":{\"type\":\"txt\",\"ans\":[\"scop\"]},\"a formalized boast\":{\"type\":\"txt\",\"ans\":[\"gielp (yelp)\"]},\"an epic short story composed in verse\":{\"type\":\"txt\",\"ans\":[\"epic poem\"]},\"Conquered Celtics\":{\"type\":\"txt\",\"ans\":[\"Rome\"]},\"The yr when people started to invade Britain\\u00a0\":{\"type\":\"txt\",\"ans\":[\"449\"]},\"The yr when the normandy king defeated english king\":{\"type\":\"txt\",\"ans\":[\"1066\"]},\"First english religious poet\":{\"type\":\"txt\",\"ans\":[\"Caedmon\"]},\"First archbishop of canterbury\":{\"type\":\"txt\",\"ans\":[\"St. Augustine\"]},\"Father of english history\":{\"type\":\"txt\",\"ans\":[\"Venerable Bede\"]},\"Responsible for translation of biblical texts, believed education was important, made the ANGLO SAXON CHRONICLE.\\u00a0\":{\"type\":\"txt\",\"ans\":[\"Alfred the Great\"]},\"A exceptional being of high authority that you watch fall throughout the story\":{\"type\":\"txt\",\"ans\":[\"Shakespearean tragic hero\"]},\"A long speech while alone\":{\"type\":\"txt\",\"ans\":[\"Soliloquy\"]},\"A long speech\":{\"type\":\"txt\",\"ans\":[\"monologue\"]},\"something in the wrong period of time\":{\"type\":\"txt\",\"ans\":[\"anachronism\"]},\"Point of no return in Macbeth\":{\"type\":\"mc\",\"op\":[\"Seeing Banquos ghost\",\"Killing Duncan\",\"Lady Macbeth killing herself\",\"The witches giving Macbeth the prophecy\"],\"ans\":[0]},\"Greatest figure of English Lit.\":{\"type\":\"txt\",\"ans\":[\"Shakespeare\"]},\"Suggest a story that is elusive and mysterious\\u00a0\":{\"type\":\"txt\",\"ans\":[\"154\"]},\"what sonnets are addressed to a young man\":{\"type\":\"txt\",\"ans\":[\"First 126\"]},\"what sonnets are also to a young man but written by a rival poet\":{\"type\":\"txt\",\"ans\":[\"Sonnets 78-86\"]},\"what sonnets are addressed to a lady with dark everything\":{\"type\":\"txt\",\"ans\":[\"Sonnets 127-152\"]},\"divides the 14 lines into two sections: an eight-line stanza (octave) rhyming ABBAABBA, and a six-line stanza (sestet) rhyming CDCDCD or CDECDE.\":{\"type\":\"txt\",\"ans\":[\"Petrarchan Sonnet\"]},\"they consist of three quatrains followed by one couplet, and they have a volta between the second and third quatrains.\":{\"type\":\"txt\",\"ans\":[\"Shakespearean Sonnet\"]},\"Has interlocked rhyme scheme\":{\"type\":\"txt\",\"ans\":[\"Spenserian Sonnet\"]},\"An unconventional comparison most often made by a suffering lover of his beautiful mistress to some physical object.\":{\"type\":\"txt\",\"ans\":[\"Conceit\"]}}}', '[21,26,1,14]', 1),
(75, 'cool', 'feller', '{\"desc\":\"\",\"contnt\":{\"asd\":{\"type\":\"txt\",\"ans\":[\"asd\"]}}}', '[5]', 1);

